import collections

class FenwickTree:
    def __init__(self, size):
        self.tree = [0] * (size + 1)
        self.size = size

    def update(self, index, val):
        while index <= self.size:
            self.tree[index] += val
            index += index & (-index)

    def query(self, index):
        s = 0
        while index > 0:
            s += self.tree[index]
            index -= index & (-index)
        return s

def count_inversions(arr):
    if not arr:
        return 0

    sorted_unique_elements = sorted(list(set(arr)))

    rank_map = {val: i + 1 for i, val in enumerate(sorted_unique_elements)}

    max_rank = len(sorted_unique_elements)

    ft = FenwickTree(max_rank)

    inversions = 0

    for num in arr:
        rank = rank_map[num]

        inversions += ft.query(max_rank) - ft.query(rank)

        ft.update(rank, 1)

    return inversions
